package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreEmptyLinesTrue() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertTrue(original.getIgnoreEmptyLines());

        CSVFormat updated = original.withIgnoreEmptyLines(true);
        assertNotNull(updated);
        assertTrue(updated.getIgnoreEmptyLines());
        // Original unchanged
        assertTrue(original.getIgnoreEmptyLines());
        assertNotSame(original, updated);
    }

    @Test
    void testWithIgnoreEmptyLinesFalse() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertTrue(original.getIgnoreEmptyLines());

        CSVFormat updated = original.withIgnoreEmptyLines(false);
        assertNotNull(updated);
        assertFalse(updated.getIgnoreEmptyLines());
        // Original unchanged
        assertTrue(original.getIgnoreEmptyLines());
        assertNotSame(original, updated);
    }

    @Test
    void testWithIgnoreEmptyLinesOnCustomFormat() {
        CSVFormat custom = CSVFormat.newFormat(';').withIgnoreEmptyLines(false);
        assertFalse(custom.getIgnoreEmptyLines());

        CSVFormat updated = custom.withIgnoreEmptyLines(true);
        assertTrue(updated.getIgnoreEmptyLines());
        assertFalse(custom.getIgnoreEmptyLines());
        assertNotSame(custom, updated);
    }
}
